#!/usr/bin/env python3
"""计算力量恢复百分比"""

import sys
import json

def calc_recovery(prev_best_kg, current_kg_or_lb, is_lb=False):
    """计算当前重量相对历史最好的恢复百分比"""
    if is_lb:
        current_kg = current_kg_or_lb * 0.4536
    else:
        current_kg = current_kg_or_lb

    if prev_best_kg == 0:
        return "N/A (无历史数据)"

    pct = (current_kg / prev_best_kg) * 100
    return f"{pct:.0f}%"

def calc_total_volume(sets):
    """计算训练总容量
    sets: list of (weight_kg, reps)
    """
    return sum(w * r for w, r in sets)

def lb_to_kg(lb):
    return lb * 0.4536

def kg_to_lb(kg):
    return kg / 0.4536

def format_recovery_table(records):
    """生成恢复情况表格
    records: list of dict {name, prev_best, current, unit}
    """
    lines = []
    lines.append("| 动作 | 之前最好 | 当前 | 恢复% |")
    lines.append("|------|---------|------|-------|")
    for r in records:
        prev = r['prev_best']
        curr = r['current']
        if r.get('unit') == 'lb':
            curr_kg = lb_to_kg(curr)
            curr_str = f"{curr}lb({curr_kg:.1f}kg)"
        else:
            curr_kg = curr
            curr_str = f"{curr}kg"

        if prev == 0:
            pct = "新动作"
        else:
            pct = f"{curr_kg/prev*100:.0f}%"

        lines.append(f"| {r['name']} | {prev}kg | {curr_str} | {pct} |")

    return "\n".join(lines)

if __name__ == "__main__":
    # CLI usage example
    if len(sys.argv) >= 3:
        prev = float(sys.argv[1])
        curr = float(sys.argv[2])
        is_lb = len(sys.argv) > 3 and sys.argv[3] == "lb"
        print(calc_recovery(prev, curr, is_lb))

